set-variable.value:
#[%dw 2.0
output application/java

---
"<!DOCTYPE html>
<html>
<head>
<meta charset='UTF-8'>

<style>
body {
    margin: 0;
    padding: 40px 0;
    background: #f4f7fb;
    font-family: Arial, Helvetica, sans-serif;
}

.container {
    width: 680px;
    margin: auto;
    background: #ffffff;
    border-radius: 16px;
    overflow: hidden;
    box-shadow: 0 12px 35px rgba(0, 0, 0, .12);
}

.header {
    background: linear-gradient(90deg, #0047AB, #0066CC);
    color: white;
    text-align: center;
    padding: 35px;
}

.logo {
    font-size: 32px;
    font-weight: bold;
}

.tagline {
    margin-top: 8px;
    font-size: 14px;
    opacity: .9;
}

.success {
    text-align: center;
    padding: 35px 30px;
}

.icon {
    width: 90px;
    height: 90px;
    line-height: 90px;
    margin: auto;
    border-radius: 50%;
    background: #16a34a;
    color: white;
    font-size: 42px;
}

.success h2 {
    color: #16a34a;
    margin-top: 20px;
    margin-bottom: 10px;
}

.success p {
    color: #555;
    line-height: 1.6;
}

.card {
    margin: 30px;
    border: 1px solid #e5e7eb;
    border-radius: 12px;
    overflow: hidden;
}

.card-title {
    background: #f8fafc;
    color: #003366;
    font-size: 20px;
    font-weight: bold;
    padding: 18px;
}

table {
    width: 100%;
    border-collapse: collapse;
}

td {
    padding: 16px;
    border-bottom: 1px solid #ececec;
}

.label {
    width: 40%;
    font-weight: bold;
    color: #555;
}

.value {
    color: #111827;
}

.status {
    color: #16a34a;
    font-weight: bold;
}

.notice {
    margin: 30px;
    background: #eef7ff;
    border-left: 6px solid #2196F3;
    padding: 20px;
    border-radius: 8px;
    color: #444;
}

.footer {
    background: #f8fafc;
    text-align: center;
    padding: 30px;
    font-size: 13px;
    color: #666;
}

.footer b {
    color: #003366;
}
</style>

</head>

<body>

<div class='container'>

<div class='header'>
    <div class='bank'>
        🏦 " ++ (payload.BANKNAME[0] default "N/A") ++ "
    </div>
    <div class='tagline'>
        Safe • Secure • Digital Banking
    </div>
</div>

<div class='success'>
    <div class='icon'>✓</div>
    <h2>Account Updated Successfully</h2>
    <p>
        Dear <b>" ++ (vars.inputPayload.FullName default "Customer") ++ "</b>,
        <br/><br/>
        Your account information has been successfully updated in our banking system.
    </p>
</div>

<div class='card'>
    <div class='card-title'>Updated Account Details</div>
    <table>
        <tr>
            <td class='label'>Reference Number</td>
            <td class='value'>" ++ (vars.transactionId default "RBK-" ++ (now() as String {format: "yyyyMMddHHmmss"})) ++ "</td>
        </tr>
        <tr>
            <td class='label'>Account Number</td>
            <td class='value'>" ++ (vars.accountNumber default "N/A") ++ "</td>
        </tr>
        <tr>
            <td class='label'>Customer Name</td>
            <td class='value'>" ++ (vars.inputPayload.FullName default "N/A") ++ "</td>
        </tr>
        <tr>
            <td class='label'>Mobile Number</td>
            <td class='value'>" ++ (vars.inputPayload.mobileNumber default "N/A") ++ "</td>
        </tr>
        <tr>
            <td class='label'>Email Address</td>
            <td class='value'>" ++ (vars.email default "N/A") ++ "</td>
        </tr>
        <tr>
            <td class='label'>Aadhaar</td>
            <td class='value'>XXXX XXXX " ++ ((vars.adharNumber as String default "XXXX XXXX")[-4 to -1]) ++ "</td>
        </tr>
        <tr>
            <td class='label'>Address</td>
            <td class='value'>" ++ (vars.inputpayload.address default "N/A") ++ "</td>
        </tr>
        <tr>
            <td class='label'>Bank Name</td>
            <td class='value'>" ++ (vars.BANKNAME default "N/A") ++ "</td>
        </tr>
        <tr>
            <td class='label'>Updated On</td>
            <td class='value'>" ++ (now() as String {format: "dd MMM yyyy hh:mm:ss a"}) ++ "</td>
        </tr>
        <tr>
            <td class='label'>Status</td>
            <td class='value status'>SUCCESS</td>
        </tr>
    </table>
</div>

<div class='notice'>
    <b>🔒 Security Notice</b>
    <br/><br/>
    If you did not request this account update, please contact our 24×7 Customer Care immediately. Protect your banking credentials and never share your OTP, PIN, CVV, or passwords with anyone.
</div>

<div class='footer'>
    <b>Real Bank</b>
    <br/><br/>
    📞 Customer Care: +91 9494207062
    <br/>
    ✉ support@realbank.com
    <br/>
    🌐 www.realbank.com
    <br/><br/>
    © 2026 Real Bank. All Rights Reserved.
    <br/><br/>
    This is an automated notification. Please do not reply to this email.
</div>

</div>

</div>

</body>

</html>"]
